import * as React from 'react';
import { graphql } from 'gatsby';
import useIntlHelper from '~src/_i18n/helpers/useIntlHelper';
import Layout from '~src/components/Layout/Layout';
import { FilmFeed } from '~src/components/Sections/Filmography/FilmFeed/FilmFeed';

const FilmographyHero = () => {
	const { formatMessage } = useIntlHelper();
	return (
		<header className="site-archive-header outer">
			<div className="inner site-header-content">
				<h1 className="site-title"> {formatMessage('navigation.projects')}</h1>
				<h2 className="site-description">{formatMessage('navigation.projects')}</h2>
			</div>
		</header>
	);
};
const FilmographyPage: React.FC<{ data }> = ({ data }) => {
	const { formatMessage } = useIntlHelper();
	return (
		<>
			<Layout template="film" header={<FilmographyHero />}>
				<div className="inner">
					<h2> {formatMessage('projects.films')}</h2>
					<FilmFeed data={data.films} />

					<h2> {formatMessage('projects.tv')}</h2>
					<FilmFeed data={data.tv} />

					<h2> {formatMessage('projects.shorts')}</h2>
					<FilmFeed data={data.shorts} />

					<h2> {formatMessage('projects.commercials')}</h2>
					<FilmFeed data={data.commercials} />

					{/* <details>
						<summary>Advertising</summary>
						<FilmFeed data={data.commercials} />
					</details> */}
				</div>
			</Layout>
		</>
	);
};
export default FilmographyPage;

export const indexQuery = graphql`
	query FilmographyPageQuery($locale: String!) {
		films: allMdx(
			sort: { fields: [frontmatter___release], order: DESC }
			filter: { fields: { locale: { eq: $locale }, category: { eq: "filmography" } }, frontmatter: { tags: { in: "film" } } }
		) {
			nodes {
				fields {
					slug
					category
				}
				frontmatter {
					title
					director
					release(formatString: "DD MMMM YYYY")
					tags
					imdb
					image {
						childImageSharp {
							gatsbyImageData(layout: FULL_WIDTH, placeholder: TRACED_SVG)
						}
					}
				}
				excerpt(truncate: true, pruneLength: 200)
				timeToRead
			}
		}
		commercials: allMdx(
			sort: { fields: [frontmatter___release], order: DESC }
			filter: { fields: { locale: { eq: $locale }, category: { eq: "filmography" } }, frontmatter: { tags: { in: "commercial" } } }
		) {
			nodes {
				fields {
					slug
					category
				}
				frontmatter {
					title
					release(formatString: "DD MMMM YYYY")
					tags
					imdb
					image {
						childImageSharp {
							gatsbyImageData(layout: FULL_WIDTH, placeholder: TRACED_SVG)
						}
					}
				}
				excerpt(truncate: true, pruneLength: 200)
				timeToRead
			}
		}
		shorts: allMdx(
			sort: { fields: [frontmatter___release], order: DESC }
			filter: { fields: { locale: { eq: $locale }, category: { eq: "filmography" } }, frontmatter: { tags: { in: "short" } } }
		) {
			nodes {
				fields {
					slug
					category
				}
				frontmatter {
					title
					release(formatString: "DD MMMM YYYY")
					tags
					imdb
					image {
						childImageSharp {
							gatsbyImageData(layout: FULL_WIDTH, placeholder: TRACED_SVG)
						}
					}
				}
				excerpt(truncate: true, pruneLength: 200)
				timeToRead
			}
		}

		tv: allMdx(
			sort: { fields: [frontmatter___release], order: DESC }
			filter: { fields: { locale: { eq: $locale }, category: { eq: "filmography" } }, frontmatter: { tags: { in: "tv" } } }
		) {
			nodes {
				fields {
					slug
					category
				}
				frontmatter {
					title
					director
					release(formatString: "DD MMMM YYYY")
					tags
					imdb
					image {
						childImageSharp {
							gatsbyImageData(layout: FULL_WIDTH, placeholder: TRACED_SVG)
						}
					}
				}
				excerpt(truncate: true, pruneLength: 200)
				timeToRead
			}
		}
	}
`;
